# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.Data.Entity;
using System.Linq;
using System.Net;
using System.Text.RegularExpressions;
using System.Web.Mvc;

namespace MyStore.Web.Controllers
{
    public class ProductController : Controller
    {
        private readonly StoreDbContext _db = new StoreDbContext();

        public ActionResult Details(int id)
        {
            var product = _db.Products
                .Include(p => p.Reviews)
                .FirstOrDefault(p => p.Id == id);

            if (product == null)
                return HttpNotFound();

            var model = new ProductDetailsViewModel
            {
                ProductId = product.Id,
                Name = product.Name,
                Description = product.Description,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAt)
                    .Select(r => new ReviewViewModel
                    {
                        Id = r.Id,
                        AuthorName = r.AuthorName,
                        CreatedAt = r.CreatedAt,
                        ContentHtml = FormatReviewContent(r.Content)
                    })
                    .ToList()
            };

            return View(model);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult AddReview(int productId, string authorName, string content)
        {
            var product = _db.Products.Find(productId);
            if (product == null)
                return HttpNotFound();

            if (string.IsNullOrWhiteSpace(authorName) || string.IsNullOrWhiteSpace(content))
            {
                TempData["ReviewError"] = "Author name and review content are required.";
                return RedirectToAction("Details", new { id = productId });
            }

            var review = new Review
            {
                ProductId = productId,
                AuthorName = authorName.Trim(),
                Content = content,
                CreatedAt = DateTime.UtcNow
            };

            _db.Reviews.Add(review);
            _db.SaveChanges();

            return RedirectToAction("Details", new { id = productId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
                _db.Dispose();

            base.Dispose(disposing);
        }

        private static string FormatReviewContent(string content)
        {
            if (string.IsNullOrEmpty(content))
                return string.Empty;

            var encoded = WebUtility.HtmlEncode(content);

            encoded = Regex.Replace(encoded, @"\*\*(.+?)\*\*", "<strong>$1</strong>", RegexOptions.Singleline);
            encoded = Regex.Replace(encoded, @"\*(.+?)\*", "<em>$1</em>", RegexOptions.Singleline);

            return encoded.Replace("\r\n", "<br />").Replace("\n", "<br />");
        }
    }

    public class ProductDetailsViewModel
    {
        public int ProductId { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public List<ReviewViewModel> Reviews { get; set; }
    }

    public class ReviewViewModel
    {
        public int Id { get; set; }
        public string AuthorName { get; set; }
        public DateTime CreatedAt { get; set; }
        public string ContentHtml { get; set; }
    }

    public class StoreDbContext : DbContext
    {
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public virtual ICollection<Review> Reviews { get; set; }
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string AuthorName { get; set; }
        public string Content { get; set; }
        public DateTime CreatedAt { get; set; }
        public virtual Product Product { get; set; }
    }
}

@model MyStore.Web.Controllers.ProductDetailsViewModel

@{
    ViewBag.Title = Model.Name;
}

<h1>@Model.Name</h1>
<p>@Model.Description</p>

<h2>Reviews</h2>

@if (TempData["ReviewError"] != null)
{
    <div class="alert alert-danger">@TempData["ReviewError"]</div>
}

@if (Model.Reviews != null && Model.Reviews.Any())
{
    <ul class="reviews">
        @foreach (var review in Model.Reviews)
        {
            <li class="review">
                <div class="review-meta">
                    <strong>@review.AuthorName</strong>
                    <span>@review.CreatedAt.ToString("g")</span>
                </div>
                <div class="review-content">
                    @Html.Raw(review.ContentHtml)
                </div>
            </li>
        }
    </ul>
}
else
{
    <p>No reviews yet.</p>
}

@using (Html.BeginForm("AddReview", "Product", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    @Html.Hidden("productId", Model.ProductId)

    <div>
        <label for="authorName">Name</label>
        <input type="text" name="authorName" id="authorName" />
    </div>

    <div>
        <label for="content">Review</label>
        <textarea name="content" id="content" rows="6"></textarea>
        <p>Use **bold** and *italic* for basic formatting.</p>
    </div>

    <button type="submit">Submit Review</button>
}